import { useNavigate } from "react-router-dom";
import StarRating from "./Rating/StarRatingByUser";
import TagCard from "./TagCard";

function CourseCard({courseInfo = {rating:0}, id = 0}) {

  const idCourse =  id.Text;

  const navigate = useNavigate()
  const crr = "#f7c41cff"
  return (
    <div className="course-card" onClick={()=> navigate("/course/"+{id})}>
      <img src={courseInfo.image} alt=""/>
      <div style={{display:"flex", flexDirection:"column", paddingRight:"6rem", position:"relative",flex:"1"}}>
        <h3>{courseInfo?.name}</h3>
        <span>{courseInfo?.description}</span>
        <ul style={{display:"flex"}}>
          {courseInfo?.tags?.map((item,index)=>(
            <li style={{listStyleType:"none", margin:"3px 2px"}}> 
              <TagCard key={index} Text={item}/>
            </li>
          ))}
        </ul>
        <p style={{display:"flex",fontSize:"1.2rem", alignItems:"center"}}>
          <span style={{marginRight:"5px", color:crr}}>{courseInfo?.rating}</span>
          <StarRating rating={courseInfo?.rating} SizeStar={16} Clr={crr}/> 
        </p>
        <div style={{position:"absolute", insetBlockStart:"5px", insetInlineEnd:"10px", textAlign:"end"}}>
          <span>{courseInfo?.price}</span>
        </div>
      </div>
    </div>
  );
}

export default CourseCard;
